import type { SearchInputConfig, ActiveCompanyItem } from '@linm-soft-org/linm-web-common-components';
import { companyService } from '../../services/company/companyService';
import { createStaticLookupSearchConfig } from './createStaticLookupSearchConfig';

/** Chi nhánh — lấy từ `companyService.getActiveList()`, filter client. */
export function createCompanySearchConfig(): SearchInputConfig<ActiveCompanyItem> {
  return createStaticLookupSearchConfig({
    loadItems: () => companyService.getActiveList(),
    getKey: item => item.id,
    getCode: item => item.code ?? item.id,
    getName: item => item.name,
    getFilterText: item => `${item.code ?? item.id} ${item.name} ${item.shortName ?? ''}`,
    codeHeaderLabel: 'Mã CN',
    nameHeaderLabel: 'Tên chi nhánh',
  });
}
