import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import {
  SEARCH_DROPDOWN_CODE_WIDTH,
  SEARCH_DROPDOWN_PORTAL,
  SEARCH_DROPDOWN_PRIMARY_WIDTH,
} from './searchDropdownDefaults';

/** LOOKUP_STATIC — filter client trên init-data, không gọi API mỗi keystroke. */
export function createStaticLookupSearchConfig<T>(opts: {
  loadItems: () => T[] | Promise<T[]>;
  getKey: (item: T) => string;
  getCode: (item: T) => string;
  getName: (item: T) => string;
  getFilterText?: (item: T) => string;
  pageSize?: number;
  codeHeaderLabel?: string;
  nameHeaderLabel?: string;
}): SearchInputConfig<T> {
  let cache: T[] | null = null;
  const load = async () => {
    if (!cache) cache = await opts.loadItems();
    return cache;
  };

  return {
    api: {
      getItemKey: opts.getKey,
      search: async ({ search, page, pageSize }) => {
        const items = await load();
        const term = (search ?? '').trim().toLowerCase();
        const filtered = term
          ? items.filter(i => {
              const hay = opts.getFilterText?.(i) ?? `${opts.getCode(i)} ${opts.getName(i)}`;
              return hay.toLowerCase().includes(term);
            })
          : items;
        const size = pageSize ?? opts.pageSize ?? 20;
        const totalPages = Math.max(1, Math.ceil(filtered.length / size));
        const start = (page - 1) * size;
        return { items: filtered.slice(start, start + size), page, totalPages };
      },
    },
    display: {
      getPrimaryDisplay: opts.getCode,
      getSecondaryDisplay: opts.getName,
      getSingleDisplay: i => `${opts.getCode(i)} — ${opts.getName(i)}`,
    },
    columns: [
      {
        key: 'code',
        variant: 'badge',
        width: SEARCH_DROPDOWN_CODE_WIDTH,
        render: opts.getCode,
      },
      {
        key: 'name',
        variant: 'primary',
        width: SEARCH_DROPDOWN_PRIMARY_WIDTH,
        render: opts.getName,
      },
    ],
    header: {
      columns: [
        { key: 'code', label: opts.codeHeaderLabel ?? 'Mã' },
        { key: 'name', label: opts.nameHeaderLabel ?? 'Tên' },
      ],
    },
    ...SEARCH_DROPDOWN_PORTAL,
    texts: { empty: 'Không tìm thấy' },
  };
}
